import xml.etree.ElementTree as ET

def parse_xml_config(filename):
    # Parse the XML file with secure options
    tree = ET.parse(filename, parser=ET.XMLParser(resolve_entities=False))

    # Extract the root element
    root = tree.getroot()

    # Create a dictionary to store the settings
    settings = {}

    # Iterate over the elements in the XML file
    for element in root.iter():
        settings[element.tag] = element.text

    # Return the dictionary of settings
    return settings